import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{r as e,o,c,a as n,b as t,e as i,f as l}from"./app-e7c604ce.js";const p={},r=l(`<h3 id="浏览器的资源一般存储在哪里" tabindex="-1"><a class="header-anchor" href="#浏览器的资源一般存储在哪里" aria-hidden="true">#</a> 浏览器的资源一般存储在哪里</h3><ol><li>资源存储的位置一共有三种，从高到低依次是<code>Service worker、Memory Cache、Disk Cache</code></li><li><code>service worker</code>：运行在主线程之外，可以完成离线缓存、消息推送、网络代理的功能。可以自由控制缓存哪些文件，怎么读取缓存。当 Service Worker 没有命中缓存的时候，需要去调用 fetch 函数获取数据。</li><li><code>Memory Cache</code>：内存缓存，它的效率最快，但是它会随着进程的释放而释放。一旦关闭tab页面，内存的缓存也被释放了。</li><li><code>Disk Cache</code>: 存储在硬盘的缓存，对比于内存缓存，读取的速度慢一些，特点是容量与时效性上更长。它会根据 HTTP请求头中的字段判断哪些资源需要缓存，哪些资源可以不请求直接使用，哪些资源已经过期需要重新请求。</li></ol><h3 id="浏览器的本地缓存" tabindex="-1"><a class="header-anchor" href="#浏览器的本地缓存" aria-hidden="true">#</a> 浏览器的本地缓存？</h3><ol><li><code>Cookie</code>：是服务端记录用户状态一种方式；由服务端生成，客户端存储。在每次同源请求都会在请求头带上Set-Cookie，如<code>Set-Cookie:name=value,domain=.;path=..</code>。它的大小只有4KB，只能被同源的页面共享，生存周期由Expired控制；</li><li><code>LocalStorage</code>：持久化存储，除非自己手动删除；最多允许存储5MB的内容，遵循同源策略，只能被同源页面访问共享；</li><li><code>SessionStorage</code>：会话存储，一般存储5M大小的数据，并且遵循同源策略。页面刷新存储的信息会在，页面关闭存储的信息会消失;</li><li>虚拟内存存储，例如:<code>全局变量、vuex、redux</code>：页面刷新或者关闭，存储的信息都会释放；</li></ol><h4 id="cookie有哪些字段-作用分别是什么" tabindex="-1"><a class="header-anchor" href="#cookie有哪些字段-作用分别是什么" aria-hidden="true">#</a> Cookie有哪些字段，作用分别是什么？</h4><ol><li><code>name value domain path expired secure HttpOnly</code></li><li><code>domain</code>是域名、<code>path</code>是路径，domain和path一起限制了cookie能够被哪些url访问；</li><li><code>expires</code>指定了cookie失效的时间；</li><li><code>secure</code>规定了cookie只能在确保安全的情况下传输；</li><li><code>HttpOnly</code>规定了cookie只能被服务器访问，不能使用js脚本访问；</li></ol><h4 id="localstorage与sessionstorage区别" tabindex="-1"><a class="header-anchor" href="#localstorage与sessionstorage区别" aria-hidden="true">#</a> LocalStorage与SessionStorage区别</h4><ol><li>共同点：都是保存在浏览器端，大小5M，都遵循同源策略。</li><li>不同点：在于生命周期与作用域的不同，作用也不同。</li><li><code>LocalStorage</code>因为是持久化，在项目可以保存用户选择的主题。</li><li><code>SessionStorage</code>具有时效性，可以用来存储一些网站的游客登录的信息，还有临时的浏览记录的信息。当关闭网站之后，这些信息也就随之消除了。</li></ol><h3 id="对浏览器缓存机制的了解" tabindex="-1"><a class="header-anchor" href="#对浏览器缓存机制的了解" aria-hidden="true">#</a> 对浏览器缓存机制的了解？</h3><p>缓存”存储在哪了? ① 内存缓存（<code>MemoryCache</code>）：页面关闭，存储的东西会消失； ② 磁盘缓存（<code>Disk Cache</code>）：持久存储，可以根据关键HTTP缓存头，减少网络请求次数。</p><h4 id="强缓存" tabindex="-1"><a class="header-anchor" href="#强缓存" aria-hidden="true">#</a> 强缓存</h4><ol><li>浏览器第一次加载资源，服务器返回<code>Cache-Control/Expires</code>，浏览器保存并缓存文件。</li><li>当请求再次发出时，浏览器会根据其中的 <code>expires：Sun,15 ay 2025 20:14:22 GMT</code> 或 <code>cache-control：max-age=2592000 </code>，判断目标资源是否“命中”强缓存。</li><li>若命中则直接从缓存中获取资源，不会再与服务端发生通信。 命中强缓存的情况下，返回的 HTTP 状态码为 200。</li></ol><h4 id="协商缓存" tabindex="-1"><a class="header-anchor" href="#协商缓存" aria-hidden="true">#</a> 协商缓存</h4><ol><li>第一次请求页面，向服务端发起请求，如果需要设置协商缓存，服务器就会在响应头返回<code>Last-Modified/Etag</code>，浏览器看到标识后会把标识与资源缓存起来。</li><li>第二次请求也会向服务器发送请求，在请求头中基于<code>If-Modified-Sine/If-None-Match</code>分别把存储的<code>Last-Modified/Etag</code>值传递给服务器。</li><li>服务器获取后比较: 如果资源没有更新过则时间或标识是一致的，服务器返回<code>304</code>，则从本地缓存获取；如果资源更新过则时间或标识是不一样的，服务器返回<code>200</code>、请求的文件以及最新的<code>Last-Modified/ETag</code>，浏览器把标识与资源缓存起来。</li><li>强缓存与协商缓存区别？</li></ol><blockquote><p>a. <code>是否向向服务器发起请求</code>：强缓存如果缓存资源有效则直接使用，不用向服务器发起请求；协商缓存会先向服务器发送一个请求，如果资源没有发生修改，则返回一个 304 状态；<br> b. <code>设置方式</code>：强缓存策略通过两种方式来设置，分别是http头信息中的<code>Expires</code>属性和<code>Cache-Control</code>属性。两种都存在时候<code>Cache-Control</code>的优先级要高于<code>Expires</code>；协商缓存通过两种方式来设置，分别是http头信息中的<code>Etag</code>和<code>Last-Modified</code>属性。</p></blockquote><h3 id="什么是同源策略" tabindex="-1"><a class="header-anchor" href="#什么是同源策略" aria-hidden="true">#</a> 什么是同源策略？</h3><ol><li>浏览器网络请求时，有一个同源策略机制：就是需要<code>协议、域名、端口</code>三者一致。</li><li>目的是为了保证用户信息的安全，对js脚本的一种限制。对于一般的<code>img</code>、或者<code>script</code>脚本请求都不会有跨域的限制</li><li>同源策略主要限制了什么？<br> a. 当前域下的js不能访问其他域的<code>cookie、storage</code>；<br> b. 当前域下的js不能操作其他域的<code>dom</code>；<br> c. 当前域下的<code>ajax</code>不能发送跨域请求；</li><li>跨域其实不是请求发不出去，请求发出去了且服务器也返回数据，但是由于同源限制所以浏览拦截了。</li></ol><h3 id="怎么解决跨域问题" tabindex="-1"><a class="header-anchor" href="#怎么解决跨域问题" aria-hidden="true">#</a> 怎么解决跨域问题？</h3><h4 id="_1-cors" tabindex="-1"><a class="header-anchor" href="#_1-cors" aria-hidden="true">#</a> 1. CORS</h4><ol><li>全称跨域资源共享（<code>Cross-Origin Resource Sharing</code>）用于控制浏览器校验跨域请求的一套规范，服务器依照<code>CORS</code>规范，添加特定响应头来控制浏览器校验。</li><li>整体思路：服务器在给出响应时，通过添加<code>Access-Control-Allow-Origin</code>响应头，来明确表达允许某个源发起跨域请求，随后浏览器在校验时通过。</li><li><code>CORS</code>会把请求分为两类，分别是：① 简单请求、② 复杂请求。简单请求有<code>get post head</code>;HTTP的头信息<code>Content-Type</code>只限于三个值：<code>application/x-www-form-urlencoded</code>、<code>multipart/form-data</code>、<code>text/plain</code>。</li></ol><h5 id="简单请求过程" tabindex="-1"><a class="header-anchor" href="#简单请求过程" aria-hidden="true">#</a> 简单请求过程</h5><ol><li>发出跨域请求后，浏览器会自动向请求头添加<code>origin</code>字段，用来说明这个请求来自哪个源；</li><li>服务器会根据这个判断是否在许可范围内，如果Origin指定的域名在许可范围内，则服务器响应头有以下：<code>Access-Control-Allow-Origin</code>、<code>Access-Control-Allow-Headers</code>、<code>Access-Control-Allow-Crediential</code>:表示是否允许发生Cookie;</li><li>不在许可范围内，服务器会返回一个正常的HTTP回应。浏览器收到响应发现没有包含<code>Access-Control-Allow-Origin</code>字段就会拦截。</li></ol><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 处理实际请求</span>
app<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token string">&#39;/students&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">(</span><span class="token parameter">req<span class="token punctuation">,</span> res</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
  <span class="token comment">// 设置允许的跨域请求源</span>
  res<span class="token punctuation">.</span><span class="token function">setHeader</span><span class="token punctuation">(</span><span class="token string">&#39;Access-Control-Allow-Origin&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;http://127.0.0.1:5500&#39;</span><span class="token punctuation">)</span>
    <span class="token comment">// 设置允许的请求方法</span>
  res<span class="token punctuation">.</span><span class="token function">setHeader</span><span class="token punctuation">(</span><span class="token string">&#39;Access-Control-Allow-Methods&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;GET&#39;</span><span class="token punctuation">)</span>
  <span class="token comment">// 设置允许暴露给客户端的响应头</span>
  res<span class="token punctuation">.</span><span class="token function">setHeader</span><span class="token punctuation">(</span><span class="token string">&#39;Access-Control-Allow-Headers&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;abc&#39;</span><span class="token punctuation">)</span>
  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;有人请求/students了&#39;</span><span class="token punctuation">)</span>
  <span class="token comment">// 发送响应数据</span>
  res<span class="token punctuation">.</span><span class="token function">send</span><span class="token punctuation">(</span>students<span class="token punctuation">)</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="复杂请求过程" tabindex="-1"><a class="header-anchor" href="#复杂请求过程" aria-hidden="true">#</a> 复杂请求过程</h5><p>先发起<code>OPTIONS</code>请求，如果通过预检，再发起实际的跨域请求。预检请求在实际跨域请求之前发出，是由浏览器自动发起的。</p><ol><li>预请求发送内容：请求方法是OPTIONS,表示查询；头信息需要有<code>origin、Access-Control-Request-Method、Access-Control-Request-Headers</code>；</li><li>服务器在收到浏览器的预检请求之后，会根据头信息的三个字段来进行判断是否允许跨源请求。如果可以则会返回：<code>Access-Control-Allow-Origin、Access-Control-Allow-Methods、Access-Control-Allow-Headers、Access-Control-Max-Age</code>本次预检的有效期；</li><li>浏览器监测到后会将实际请求发送到服务器，然后服务器返回我们需要的资源；如果没有，就是不同意这个预检请求，浏览器会阻止跨域访问，实际的请求永远不会被发送。</li></ol><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// nodejs处理预检请求</span>
app<span class="token punctuation">.</span><span class="token function">options</span><span class="token punctuation">(</span><span class="token string">&#39;/students&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">(</span><span class="token parameter">req<span class="token punctuation">,</span> res</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
  <span class="token comment">// 设置允许的跨域请求源</span>
  res<span class="token punctuation">.</span><span class="token function">setHeader</span><span class="token punctuation">(</span><span class="token string">&#39;Access-Control-Allow-Origin&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;http://127.0.0.1:5100&#39;</span><span class="token punctuation">)</span>
  <span class="token comment">// 设置允许的请求方法</span>
  res<span class="token punctuation">.</span><span class="token function">setHeader</span><span class="token punctuation">(</span><span class="token string">&#39;Access-Control-Allow-Methods&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;GET&#39;</span><span class="token punctuation">)</span>
  <span class="token comment">// 设置允许的请求头</span>
  res<span class="token punctuation">.</span><span class="token function">setHeader</span><span class="token punctuation">(</span><span class="token string">&#39;Access-Control-Allow-Headers&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;school&#39;</span><span class="token punctuation">)</span>
  <span class="token comment">// 设置预检请求的缓存时间（可选）</span>
  res<span class="token punctuation">.</span><span class="token function">setHeader</span><span class="token punctuation">(</span><span class="token string">&#39;Access-Control-Max-Age&#39;</span><span class="token punctuation">,</span> <span class="token number">7200</span><span class="token punctuation">)</span>
  <span class="token comment">// 发送响应</span>
  res<span class="token punctuation">.</span><span class="token function">send</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_2-proxy代理" tabindex="-1"><a class="header-anchor" href="#_2-proxy代理" aria-hidden="true">#</a> 2. proxy代理</h4><ol><li>通过开启一个代理服务器，实现数据的转发。</li><li>原理就是利用服务器与服务器之间不存在跨域来实现。在本地启动一个服务，代理服务器与前端所处的协议主机端口一样，它收到本次的请求把请求转发给目的服务器，等到收到返回数据再返回给前端；</li><li>vue-cli开启代理服务器，在<code>vue.config.js</code>配置<code>devServer的proxy</code>选项。如果在proxy里面加上<code>&quot;/api&quot;:{target:&#39;&#39;}</code>，那么以<code>&quot;/api&quot;</code>开始的请求就被发送到代理服务器。</li></ol><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token literal-property property">devServer</span><span class="token operator">:</span><span class="token punctuation">{</span>
  <span class="token comment">//配置跨域代理，可以配置对多台服务器的代理</span>
  <span class="token literal-property property">proxy</span><span class="token operator">:</span>
    <span class="token comment">//以&quot;/api&quot;开始的请求，都发送到代理服务器</span>
    <span class="token string-property property">&quot;/api&quot;</span><span class="token operator">:</span><span class="token punctuation">{</span>
        <span class="token literal-property property">target</span><span class="token operator">:</span><span class="token string">&quot;https://www.baidu.com/aa&quot;</span><span class="token punctuation">,</span>
        <span class="token literal-property property">changeOrigin</span><span class="token operator">:</span><span class="token boolean">true</span><span class="token punctuation">,</span> <span class="token comment">//改变origin源</span>
        <span class="token literal-property property">pathRewrite</span><span class="token operator">:</span><span class="token punctuation">{</span><span class="token string-property property">&quot;^/api&quot;</span><span class="token operator">:</span><span class="token string">&quot;&quot;</span><span class="token punctuation">}</span><span class="token punctuation">,</span>
    <span class="token punctuation">}</span>
    <span class="token comment">//以&quot;/api1&quot;开始的请求，都发送到代理服务器</span>
    <span class="token string-property property">&quot;/api1&quot;</span><span class="token operator">:</span><span class="token punctuation">{</span>
      <span class="token literal-property property">target</span><span class="token operator">:</span><span class="token string">&quot;https://nnn.baidu.com/bb&quot;</span><span class="token punctuation">,</span>
      <span class="token literal-property property">changeOrigin</span><span class="token operator">:</span><span class="token boolean">true</span><span class="token punctuation">,</span>
      <span class="token literal-property property">pathRewrite</span><span class="token operator">:</span><span class="token punctuation">{</span><span class="token string-property property">&quot;^/api1&quot;</span><span class="token operator">:</span><span class="token string">&quot;&quot;</span><span class="token punctuation">}</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_3-nginx代理跨域" tabindex="-1"><a class="header-anchor" href="#_3-nginx代理跨域" aria-hidden="true">#</a> 3. nginx代理跨域</h4><ol><li>nginx配置解决iconfont跨域</li><li>跨域访问js、css、img等常规静态资源被同源策略许可，但iconfont字体文件不行，<code>location / {add_header Access-Control-Allow-Origin *;}</code></li></ol><h3 id="浏览器安全机制" tabindex="-1"><a class="header-anchor" href="#浏览器安全机制" aria-hidden="true">#</a> 浏览器安全机制？</h3><h4 id="xss攻击" tabindex="-1"><a class="header-anchor" href="#xss攻击" aria-hidden="true">#</a> XSS攻击</h4><ol><li>是什么？XSS（<code>Cross Site Scripting</code>）跨站脚本攻击，是使用注入恶意脚本的攻击手段。XSS攻击是指黑客往HTML文件中或者DOM中注入恶意脚本，从而在用户浏览页面时利用注入的恶意脚本对用户实施攻击的一种手段。</li><li>页面被注入了恶意 JavaScript 脚本，恶意脚本可以：可以窃取 Cookie 信息；监听用户行为，比如获取用户输入的信用卡等信息；在页面内生成浮窗广告；</li><li>种类：<code>存储型XSS攻击；反射型XSS攻击；基于DOM的XSS攻击</code>，这三种攻击方式的共同点是都需要往用户的页面中注入恶意脚本，然后再通过恶意脚本将用户数据上传到黑客的恶意服务器上。</li><li>阻止XSS攻击：① 服务器对输入的脚本进行过滤和转码，如过滤<code>&lt;script&gt;</code>标签；② 使用<code>HttpOnly</code>属性，当<code>HttpOnly</code>被设置为<code>true</code>的时候，无法通过js脚本读取到<code>cookie</code>的数据，一些重要的数据设置<code>HttpOnly</code>标志；③ 利用<code>CSP</code>：比如限制加载其他域下的资源文件；</li></ol><h4 id="csrf攻击" tabindex="-1"><a class="header-anchor" href="#csrf攻击" aria-hidden="true">#</a> CSRF攻击</h4><ol><li>是什么？（<code>Cross-site request forgery</code>）跨站请求伪造，利用用户的登录状态发起的跨站请求，并通过第三方站点来做一些坏事。</li><li>需满足三个条件：① 目标站点一定要有CSRF漏洞；② 用户要登录过目标站点，并且在浏览器上保持有该站点的登录状态；③ 用户需要打开第三方站点，引诱用户点击链接：比点击美女图片下载地址，而这个下载地址实际上是黑客用来转账的接口，一旦用户点击了这个链接并登录了xx软件，那么软件的钱就被转到黑客账户上了。</li><li>防止CSRF攻击，主要是提升服务器的安全性：</li></ol><blockquote><p>a. 利用好Cookie的<code>sameSite</code>属性,HTTP响应头中，通过<code>set-cookie</code>字段设置<code>Cookie</code>,可以带上<code>SameSite</code>选项,<code>Strict</code>值浏览器会完全禁止第三方Cookie；<code>Lax</code>值在第三方站点中使用Post方法，或者通过<code>img、iframe</code>等标签加载的URL，这些场景都不会携带Cookie；<br> b. 验证请求的来源站点，使用HTTP请求的<code>Referer</code>和<code>Origin</code>属性。<code>Referer</code>记录了该HTTP请求的来源地址;<br> c. 采用CSRF的<code>Token</code>来验证;</p></blockquote><h3 id="浏览器的垃圾回收机制" tabindex="-1"><a class="header-anchor" href="#浏览器的垃圾回收机制" aria-hidden="true">#</a> 浏览器的垃圾回收机制？</h3><ol><li>是什么是垃圾回收？ js代码运行时，需要存储空间来存储变量和值。js它有自动的垃圾回收机制，会定期对那些不再使用的变量、对象所占用的内存进行释放。</li><li>垃圾回收的方式？ 标记清除与引用计数。</li><li>标记清除？是浏览器最常用的垃圾回收方式，当变量进入执行环境时候，会标记这个变量进入环境，因为正被使用，所以变量不能回收；变量离开环境时候，被标记离开环境，这时变量会被内存释放。</li><li>怎么减少垃圾回收？对象尽量复用，对于不再使用的对象，就将其设置为 null，尽快被回收。</li></ol><h3 id="链接" tabindex="-1"><a class="header-anchor" href="#链接" aria-hidden="true">#</a> 链接</h3>`,41),d={href:"https://time.geekbang.org/column/article/151370",target:"_blank",rel:"noopener noreferrer"};function u(k,h){const s=e("ExternalLinkIcon");return o(),c("div",null,[r,n("p",null,[n("a",d,[t("浏览器工作原理与实践"),i(s)])])])}const g=a(p,[["render",u],["__file","浏览器的缓存、跨域与安全.html.vue"]]);export{g as default};
